(()=>{var c=document.querySelectorAll(".spanish"),e=document.querySelectorAll(".english");e.forEach((function(c){c.classList.add("hidden")})),c.forEach((function(c){c.classList.add("block")})),document.getElementById("lang-en").addEventListener("click",(function(){e.forEach((function(c){c.classList.remove("hidden"),c.classList.add("block")})),c.forEach((function(c){c.classList.remove("block"),c.classList.add("hidden")}))})),document.getElementById("lang-es").addEventListener("click",(function(){e.forEach((function(c){c.classList.remove("block"),c.classList.add("hidden")})),c.forEach((function(c){c.classList.remove("hidden"),c.classList.add("block")}))}))})();